    DailyWird(text: '﴿ يَومَ تَجِدُ كُلُّ نَفسٍ ما عَمِلَت مِن خَيرٍ مُحضَرًا وَما عَمِلَت مِن سوءٍ تَوَدُّ لَو أَنَّ بَينَها وَبَينَهُ أَمَدًا بَعيدًا وَيُحَذِّرُكُمُ اللَّهُ نَفسَهُ وَاللَّهُ رَءوفٌ بِالعِبادِ ﴾', source: 'آل عمران: 30', type: 'verse'),
    DailyWird(text: '﴿ اقرَأ كِتابَكَ كَفى بِنَفسِكَ اليَومَ عَلَيكَ حَسيبًا ﴾', source: 'الإسراء: 14', type: 'verse'),
    DailyWird(text: '﴿ فَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ خَيْرًا يَرَهُ * وَمَنْ يَعْمَلْ مِثْقَالَ ذَرَّةٍ شَرًّا يَرَهُ ﴾', source: 'الزلزلة: 7-8', type: 'verse'),
    DailyWird(text: '﴿ وَأَقيمُوا الصَّلاةَ وَآتُوا الزَّكاةَ وَما تُقَدِّموا لِأَنفُسِكُم مِن خَيرٍ تَجِدوهُ عِندَ اللَّهِ إِنَّ اللَّهَ بِما تَعمَلونَ بَصيرٌ ﴾', source: 'البقرة: 110', type: 'verse'),
