    DailyWird(text: '﴿ ما أَصابَ مِن مُصيبَةٍ إِلّا بِإِذنِ اللَّهِ وَمَن يُؤمِن بِاللَّهِ يَهدِ قَلبَهُ وَاللَّهُ بِكُلِّ شَيءٍ عَليمٌ ﴾', source: 'التغابن: 11', type: 'verse'),
    DailyWird(text: '﴿ إِن يَعلَمِ اللَّهُ في قُلوبِكُم خَيرًا يُؤتِكُم خَيرًا مِمّا أُخِذَ مِنكُم وَيَغفِر لَكُم وَاللَّهُ غَفورٌ رَحيمٌ ﴾', source: 'الأنفال: 70', type: 'verse'),
