    DailyWird(text: '﴿ قُل إِنَّ صَلاتي وَنُسُكي وَمَحيايَ وَمَماتي لِلَّهِ رَبِّ العالَمينَ ﴾', source: 'الأنعام: 162', type: 'verse'),
    DailyWird(text: '﴿ وَمِنَ النّاسِ مَن يَشري نَفسَهُ ابتِغاءَ مَرضاتِ اللَّهِ وَاللَّهُ رَءوفٌ بِالعِبادِ ﴾', source: 'البقرة: 207', type: 'verse'),
