  static final List<DailyWird> _hadiths = [
    DailyWird(text: '«يَعقِدُ الشَّيطانُ على قافيةِ رَأسِ أحَدِكُم إذا هو نامَ ثَلاثَ عُقدٍ، يَضرِبُ كُلَّ عُقدةٍ: عليك لَيلٌ طَويلٌ فارقُدْ، فإنِ استَيقَظَ فذَكَرَ اللهَ انحَلَّت عُقدةٌ، فإن تَوضَّأ انحَلَّت عُقدةٌ، فإن صَلَّى انحَلَّت عُقدةٌ، فأصبَحَ نَشيطًا طَيِّبَ النَّفسِ، وإلَّا أصبَحَ خَبيثَ النَّفسِ كَسلانَ».', source: 'رواه البخاري', narrator: 'أبو هريرة', type: 'hadith'),
    DailyWird(text: '«ألا أدُلُّكما على خيرٍ ممَّا سألتما؟ إذا أخذتما مضاجعكما - أو أويتما إلى فراشكما - فسبِّحا ثلاثًا وثلاثين، واحمدا ثلاثًا وثلاثين، وكبِّرا أربعًا وثلاثين؛ فهو خيرٌ لكما من خادم».', source: 'رواه البخاري', narrator: 'علي بن أبي طالب', type: 'hadith'),
    DailyWird(text: '«ألا أُخبِرُكم مَن المسلم؟ مَن سلِم المسلمون من لسانه ويده، والمؤمنُ مَن أمِنَه الناسُ على أموالهم وأنفسهم، والمهاجرُ مَن هجَر الخطايا والذنوب، والمجاهدُ مَن جاهَد نفسه في طاعة الله».', source: 'شعيب الأرناؤوط', narrator: 'فضالة بن عبيد', type: 'hadith'),
    DailyWird(text: '«المؤمنُ القويُّ خيرٌ وأحبُّ إلى اللهِ مِن المؤمنِ الضعيف، وفي كلٍّ خير. احرِص على ما ينفعك، واستعِن بالله ولا تعجز، وإن أصابك شيء فلا تقل: لو أنِّي فعلتُ كان كذا وكذا، ولكن قل: قدَرُ الله وما شاء فعل؛ فإنَّ لو تفتح عمل الشيطان».', source: 'رواه مسلم', narrator: 'أبو هريرة', type: 'hadith'),
    DailyWird(text: '«احرص على ما ينفعك واستعن بالله ولا تعجز».', source: 'رواه مسلم', narrator: 'أبو هريرة', type: 'hadith'),
