  static Map<String, DailyWird> getDailyWirdBundle() {
    final now = DateTime.now();
    final dayOfYear = now.difference(DateTime(now.year, 1, 1)).inDays;
    
    final verse = _verses[dayOfYear % _verses.length];
    final hadith = _hadiths[dayOfYear % _hadiths.length];
    final wisdom = _wisdoms[dayOfYear % _wisdoms.length];
    
    return {'verse': verse, 'hadith': hadith, 'wisdom': wisdom};
  }

  static DailyWird getRandomWird() {
    final combined = [..._verses, ..._hadiths, ..._wisdoms];
    return combined[Random().nextInt(combined.length)];
  }
}
